#!/usr/bin/env node

import { execFileSync, spawn, spawnSync } from 'node:child_process'
import { existsSync, readFileSync, realpathSync } from 'node:fs'
import { createRequire } from 'node:module'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const repoRoot = dirname(dirname(fileURLToPath(import.meta.url)))
const require = createRequire(import.meta.url)

// Lockfiles are regenerated by the package manager as a side effect of
// `install`, so a checkout that's been built or updated once carries a dirty,
// machine-authored lockfile. That drift makes `git pull --ff-only` abort with
// "local changes would be overwritten by merge" — the exact failure users hit
// running `praxis --update`. Since the update reinstalls right after pulling
// (regenerating the lockfile against the new package.json), it's safe to
// discard the drift first. Kept as a pure helper so it's unit-testable.
const LOCKFILES = new Set([
  'bun.lock',
  'bun.lockb',
  'package-lock.json',
  'npm-shrinkwrap.json',
  'yarn.lock',
  'pnpm-lock.yaml',
])

/**
 * Given `git status --porcelain` output, return the tracked lockfiles that are
 * dirty (staged and/or unstaged) and should be restored to HEAD before a pull.
 * Untracked ('??') entries are ignored — there's nothing at HEAD to restore.
 */
export function lockfilesToRestore(porcelain) {
  const restore = []
  for (const line of String(porcelain).split('\n')) {
    if (line.length < 4) continue
    const status = line.slice(0, 2)
    if (status === '??') continue
    // porcelain paths start at column 3; renames read "old -> new" (not a
    // lockfile concern, but take the post-rename path if it ever occurs).
    const raw = line.slice(3).trim()
    const path = raw.includes(' -> ') ? raw.slice(raw.indexOf(' -> ') + 4) : raw
    if (LOCKFILES.has(path)) restore.push(path)
  }
  return restore
}

function detectPackageManager() {
  const check = spawnSync('bun', ['--version'], { stdio: 'ignore' })
  return !check.error && check.status === 0 ? 'bun' : 'npm'
}

function usage() {
  return `Usage: praxis [command]

Commands:
  praxis              Launch Praxis (builds first if needed)
  praxis --update      Pull latest changes, reinstall, and rebuild
  praxis --help        Show this help message
  praxis --version      Print the installed version
`
}

function getElectronPath() {
  try {
    return require('electron')
  } catch {
    console.error(`Praxis isn't installed yet — run: ${detectPackageManager()} install`)
    process.exit(1)
  }
}

function printVersion() {
  const pkgPath = join(repoRoot, 'package.json')
  const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'))
  console.log(`Praxis ${pkg.version}`)
}

function launch() {
  const builtEntry = join(repoRoot, 'out', 'main', 'index.js')

  if (!existsSync(builtEntry)) {
    const buildResult = spawnSync(detectPackageManager(), ['run', 'build'], {
      cwd: repoRoot,
      stdio: 'inherit',
    })
    if (buildResult.status !== 0) {
      console.error('Praxis build failed — see output above.')
      process.exit(buildResult.status ?? 1)
    }
  }

  const electronPath = getElectronPath()

  const child = spawn(electronPath, ['.'], {
    cwd: repoRoot,
    detached: true,
    stdio: 'ignore',
  })
  child.unref()

  console.log('Launching Praxis…')
  process.exit(0)
}

function update() {
  let before
  try {
    before = execFileSync('git', ['rev-parse', '--short', 'HEAD'], {
      cwd: repoRoot,
    })
      .toString()
      .trim()
  } catch {
    console.error('Could not determine current git revision.')
    process.exit(1)
  }

  // Drop machine-generated lockfile drift so `git pull --ff-only` doesn't abort
  // on it; `install` below rebuilds the lockfile against the pulled package.json.
  const status = spawnSync('git', ['status', '--porcelain'], {
    cwd: repoRoot,
    encoding: 'utf8',
  })
  if (status.status === 0) {
    const dirtyLocks = lockfilesToRestore(status.stdout)
    if (dirtyLocks.length > 0) {
      console.log(
        `Discarding local ${dirtyLocks.join(', ')} changes (regenerated on install)…`,
      )
      spawnSync('git', ['checkout', 'HEAD', '--', ...dirtyLocks], {
        cwd: repoRoot,
        stdio: 'inherit',
      })
    }
  }

  const pm = detectPackageManager()
  const steps = [
    ['git', ['pull', '--ff-only']],
    [pm, ['install']],
    [pm, ['run', 'build']],
  ]

  for (const [cmd, args] of steps) {
    const result = spawnSync(cmd, args, { cwd: repoRoot, stdio: 'inherit' })
    if (result.status !== 0) {
      console.error(
        `Update failed while running \`${cmd} ${args.join(' ')}\` (exit code ${result.status}).` +
          (cmd === 'git'
            ? ' If you have local changes, commit or stash them and try again.'
            : ''),
      )
      process.exit(result.status ?? 1)
    }
  }

  const after = execFileSync('git', ['rev-parse', '--short', 'HEAD'], {
    cwd: repoRoot,
  })
    .toString()
    .trim()

  if (before === after) {
    console.log('Praxis is already up to date.')
  } else {
    console.log(`Updated ${before} → ${after}.`)
  }

  console.log('Run `praxis` to (re)start.')
  process.exit(0)
}

function main() {
  const args = process.argv.slice(2)
  const command = args[0]

  if (command === undefined) {
    launch()
    return
  }

  if (command === '--update' || command === 'update') {
    // --no-launch is accepted (passed by the in-app updater) and ignored,
    // since update() never auto-launches regardless.
    update()
    return
  }

  if (command === '--help' || command === '-h') {
    console.log(usage())
    process.exit(0)
    return
  }

  if (command === '--version' || command === '-v') {
    printVersion()
    process.exit(0)
    return
  }

  console.error(`Unknown command: ${command}\n`)
  console.error(usage())
  process.exit(1)
}

// Run the CLI only when invoked as a script (directly or via the PATH symlink
// install.sh creates), not when imported by a test. realpath both sides so the
// symlink and its target compare equal. Default to running on any error — a
// real CLI invocation always has a resolvable argv[1], so a throw here only
// happens in edge cases where no-op'ing the command would be worse.
function invokedAsScript() {
  try {
    return realpathSync(process.argv[1]) === realpathSync(fileURLToPath(import.meta.url))
  } catch {
    return true
  }
}

if (invokedAsScript()) main()
